const input = $('Set Input').first().json;
const prompt = $input.first().json;

let userPrompt = prompt.user_prompt_template;
userPrompt = userPrompt.replace('{{topic}}', input.topic);
userPrompt = userPrompt.replace('{{context}}', input.difficulty || 'intermediate');

return [{
  json: {
    system_prompt: prompt.system_prompt,
    user_prompt: userPrompt,
    topic: input.topic,
    platform: input.platform,
    quiz_type: input.quiz_type,
    comment_delay_hours: input.comment_delay_hours || 4
  }
}];

function escapeSql(str) {
  if (!str) return '';
  return str.replace(/'/g, "''");
}

const ollamaResponse = $input.first().json;
const prepData = $('Prepare Prompt').first().json;
const rawContent = ollamaResponse.message?.content || '{}';

// Try to parse JSON from Ollama response
let quizData;
try {
  // Remove markdown code blocks if present
  const cleaned = rawContent.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  quizData = JSON.parse(cleaned);
} catch (e) {
  return [{ json: { error: 'Failed to parse quiz JSON: ' + e.message, raw: rawContent } }];
}

// Format the post text (question only, no answer)
let postText = '';
if (quizData.question_scenario) {
  postText += quizData.question_scenario + '\n\n';
}
postText += quizData.question + '\n\n';
postText += 'A. ' + quizData.options.A + '\n';
postText += 'B. ' + quizData.options.B + '\n';
postText += 'C. ' + quizData.options.C + '\n';
postText += 'D. ' + quizData.options.D + '\n\n';
postText += '💬 Comment đáp án của bạn!\n';
postText += '⏰ Đáp án sẽ được công bố sau ' + prepData.comment_delay_hours + ' giờ\n\n';
postText += '#' + (quizData.tags || ['TechQuiz']).join(' #');

// Format the answer comment
let answerText = '✅ Đáp án: ' + quizData.correct_answer + '\n\n';
answerText += '📖 Giải thích:\n' + quizData.explanation + '\n\n';
if (quizData.wrong_explanations) {
  Object.entries(quizData.wrong_explanations).forEach(([key, val]) => {
    answerText += '❌ ' + key + ': ' + val + '\n';
  });
  answerText += '\n';
}
if (quizData.key_concepts && quizData.key_concepts.length > 0) {
  answerText += '💡 Key concepts:\n';
  quizData.key_concepts.forEach(c => {
    answerText += '• ' + c.name + ': ' + c.description + '\n';
  });
}
answerText += '\n🔖 Save bài này để ôn thi!';

// Build quiz_answer JSON for DB
const quizAnswerJson = JSON.stringify({
  correct_answer: quizData.correct_answer,
  explanation: quizData.explanation,
  wrong_explanations: quizData.wrong_explanations || {},
  key_concepts: quizData.key_concepts || [],
  formatted_comment: answerText
});

return [{
  json: {
    title: escapeSql(prepData.topic),
    platform: escapeSql(prepData.platform),
    pillar: 'tech_insights',
    content_type: 'quiz',
    generated_content: escapeSql(postText),
    quiz_answer: quizAnswerJson,
    comment_delay_hours: prepData.comment_delay_hours,
    status: 'pending_review',
    answer_preview: answerText
  }
}];

